#include <bits/stdc++.h>
using namespace std;

const int N=1e6+6,mod=1e9+7;

int n,h[N][2],T,mi[N];
char s[N];

int Hash(int l,int r,bool tp){
    if(!tp)
        return ((h[r][0]-1LL*h[l-1][0]*mi[r-l+1]%mod)%mod+mod)%mod;
    else
        return ((h[l][1]-1LL*h[r+1][1]*mi[r-l+1]%mod)%mod+mod)%mod;
}

bool check(int x){
    if(!x)
        return 1;
    for(int i=1;i<=n-x+1;i++)
        if(Hash(i,i+x-1,0)==Hash(i,i+x-1,1))
            return 1;
    return 0;
}

int main(){
    mi[0]=1;
    for(int i=1;i<N;i++)
        mi[i]=1LL*mi[i-1]*29%mod;
    while(1){
        scanf("%s",s+1);
        if(s[1]=='E')
            break;
        n=strlen(s+1);
        h[n+1][1]=h[0][0]=0;
        for(int i=1;i<=n;i++)
            h[i][0]=(1LL*h[i-1][0]*29%mod+s[i]-'a')%mod;
        for(int i=n;i;i--)
            h[i][1]=(1LL*h[i+1][1]*29%mod+s[i]-'a')%mod;
        int l=1,r=(n+1)/2;
        while(l<r){
            int mid=l+r+1>>1;
            if(check(2*mid-1))
                l=mid;
            else
                r=mid-1;
        }
        int tmp=2*l-1;
        l=0,r=n/2;
        while(l<r){
            int mid=l+r+1>>1;
            if(check(2*mid))
                l=mid;
            else
                r=mid-1;
        }
        printf("Case %d: %d\n",++T,max(2*l,tmp));
    }
    return 0;
}
